node -e "
const fs = require\('fs'\);
const path = require\('path'\);
const glob = require\('glob'\);

// Get all product sub-pages
let files = glob.sync\('src/app/products/channel-letters/*/page.tsx'\);
files.push\(
  'src/app/products/blade-signs/page.tsx',
  'src/app/products/flat-cut-letters/page.tsx',
  'src/app/products/lightboxes/page.tsx',
  'src/app/products/seg-light-boxes/page.tsx',
  'src/app/products/custom-fabrication/page.tsx',
  'src/app/products/channel-letters/page.tsx',
\);

for \(const fpath of files\) {
  if \(!fs.existsSync\(fpath\)\) { console.log\('SKIP:', fpath\); continue; }

  let content = fs.readFileSync\(fpath, 'utf-8'\);
  const original = content;

  // 1. Remove trailing spacer div
  content = content.replace\(/\\s*<div className=\\"h-20 lg:hidden\\" \\/>\\s*/g, '\\n'\);

  // 2. Ensure CTASection import
  if \(!content.includes\('CTASection'\)\) {
    content = content.replace\(
      'import AnimatedSection from \\"@/components/AnimatedSection\\";',
      'import AnimatedSection from \\"@/components/AnimatedSection\\";\\nimport CTASection from \\"@/components/CTASection\\";'
    \);
  }

  // 3. Replace last CTA section with <CTASection />
  // Find the last {/* CTA */} marker and replace everything from there to the closing </>
  const ctaMarkerIdx = content.lastIndexOf\('{/* CTA */}'\);
  if \(ctaMarkerIdx !== -1\) {
    const closingIdx = content.indexOf\('</>', ctaMarkerIdx\);
    if \(closingIdx !== -1\) {
      // Find the start of the line with {/* CTA */}
      let lineStart = content.lastIndexOf\('\\\\n', ctaMarkerIdx\);
      if \(lineStart === -1\) lineStart = 0;

      const before = content.substring\(0, lineStart\);
      const after = content.substring\(closingIdx\);

      content = before + '\\\\n\\\\n      <CTASection />\\\\n    ' + after;
    }
  }

  // 4. Remove unused Lock import if CTA section removed it \(Lock was only used there in some files\)
  // Skip this - Lock is used in hero sections too

  if \(content !== original\) {
    fs.writeFileSync\(fpath, content, 'utf-8'\);
    console.log\('Updated:', fpath\);
  } else {
    console.log\('No change:', fpath\);
  }
}
console.log\('Done'\);
")
